A user reports: "I update my email in settings but when I refresh the page, the old email is back." You check the Network tab and see a PUT request to `/api/user/settings` with status `200 OK`. What is the most likely problem?

```typescript
function SettingsForm({ user }: { user: User }) {
  const [email, setEmail] = useState(user.email);

  async function handleSave() {
    await fetch('/api/user/settings', {
      method: 'PUT',
      body: JSON.stringify({ email }),
    });
    alert('Settings saved!');
  }

  return (
    <form onSubmit={(e) => { e.preventDefault(); handleSave(); }}>
      <input value={email} onChange={(e) => setEmail(e.target.value)} />
      <button type="submit">Save</button>
    </form>
  );
}
```

A team reports: "The dashboard works in development but shows a blank white screen in production. No errors in the console." You check the Network tab in production and see all API calls returning `200 OK`. What should you check next?

```typescript
function Dashboard() {
  const { data, isLoading } = useQuery(['metrics'], fetchMetrics);

  if (isLoading) return <LoadingSpinner />;

  return (
    <div>
      <h1>Dashboard</h1>
      {data.metrics.map((m) => (
        <MetricCard key={m.id} metric={m} />
      ))}
    </div>
  );
}
```

A user reports: "When I click 'Load More', nothing happens the second time." Walk through the checklist. Which step reveals the problem?

```typescript
function InfiniteList() {
  const [items, setItems] = useState<Item[]>([]);
  const [page, setPage] = useState(1);
  const [loading, setLoading] = useState(false);

  async function loadMore() {
    if (loading) return;
    setLoading(true);

    const response = await fetch(`/api/items?page=${page}`);
    const newItems = await response.json();

    setItems([...items, ...newItems]);
    setLoading(false);
  }

  return (
    <div>
      {items.map((item) => <ItemCard key={item.id} item={item} />)}
      <button onClick={loadMore} disabled={loading}>
        {loading ? 'Loading...' : 'Load More'}
      </button>
    </div>
  );
}
```
